    function getStatusTone(message) {
        const text = String(message || "").toLowerCase();
        if (!text) {
            return "info";
        }
        if (text.includes("connected") || text.includes("authenticated") || text.includes("ready")) {
            return "success";
        }
        if (text.includes("expired") || text.includes("mismatch") || text.includes("invalid") || text.includes("revoked") || text.includes("failed")) {
            return "error";
        }
        return "info";
    }

    function applyStatusMessage(statusNode, message) {
        if (!statusNode) {
            return;
        }
        statusNode.textContent = message || "Session required";
        statusNode.dataset.tone = getStatusTone(message);
    }

